namespace TicketClassifier.Models;

/// <summary>
/// Holds label names in score-array order, extracted from the trained model.
/// Registered as a singleton so the controller can map scores to labels.
/// </summary>
public sealed class ModelMetadata
{
    public required string[] Labels { get; init; }
}

toolArgs.new_str:
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model at startup and log evaluation metrics
using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var trainer = new ModelTrainingService(loggerFactory.CreateLogger<ModelTrainingService>());
trainer.TrainAndEvaluate();

// Register label metadata so the controller can map score indices to names
builder.Services.AddSingleton(new ModelMetadata { Labels = trainer.Labels });

// Thread-safe prediction engine pool
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

